import { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { pb } from "@/lib/pocketbase";
import { Loader2, AlertTriangle, Smartphone, ExternalLink, MoreVertical, X, Share2, Compass } from "lucide-react";
import PublicProfile from "./PublicProfile";

export default function RedirectHandler() {
    const { username } = useParams();
    const navigate = useNavigate();
    const [status, setStatus] = useState<"loading" | "verifying" | "error" | "deeplink" | "profile">("loading");
    const [error, setError] = useState<string | null>(null);
    const [linkData, setLinkData] = useState<any>(null);
    const [destination, setDestination] = useState<string>("");

    useEffect(() => {
        const handleRedirect = async () => {
            if (!username) return;

            // Handle legacy /u/ prefix if it comes through the catch-all
            if (username.startsWith("u/")) {
                const cleanSlug = username.replace("u/", "");
                navigate(`/${cleanSlug}`, { replace: true });
                return;
            }

            const effectiveSlug = username;

            try {
                // 1. Fetch Link Data
                let link = null;
                try {
                    link = await pb.collection('links').getFirstListItem(`slug="${effectiveSlug}"`);
                } catch (e) {
                    // Link not found, check for User Profile (Aesthetic URL)
                    try {
                        const userProfile = await pb.collection('users').getFirstListItem(`username="${effectiveSlug}"`);
                        if (userProfile) {
                            setStatus("profile");
                            return;
                        }
                    } catch (userErr) {
                        // Neither link nor user found
                        setStatus("error");
                        setError("Link not found or inactive");
                        return;
                    }
                }

                setLinkData(link);
                // ... (rest of useEffect logic using username instead of slug)

                if (!link || !link.active) {
                    setStatus("error");
                    setError("Link not found or inactive");
                    return;
                }

                // Check link scheduling
                const now = new Date();
                if (link.start_at && new Date(link.start_at) > now) {
                    setStatus("error");
                    setError("This link is not yet active");
                    return;
                }
                if (link.expire_at && new Date(link.expire_at) < now) {
                    setStatus("error");
                    setError("This link has expired");
                    return;
                }

                const ua = navigator.userAgent;
                const isBot = /bot|crawler|spider|criteo|facebook|google|bing|twitter|linkedin|instagram|tiktok/i.test(ua);
                const isInstagram = /Instagram/i.test(ua);
                const isTikTok = /TikTok/i.test(ua);
                const isFacebook = /FBAN|FBAV/i.test(ua);
                const isInApp = isInstagram || isTikTok || isFacebook;

                // 2. Link Optimization (Bot Check)
                if (link.cloaking && isBot && link.safe_page_url) {
                    console.log("Bot detected, optimizing to safe page");
                    window.location.replace(link.safe_page_url);
                    return;
                }

                // 3. Analytics Data
                let os = "Other";
                if (/Windows/i.test(ua)) os = "Windows";
                else if (/iPhone|iPad|iPod/i.test(ua)) os = "iOS";
                else if (/Android/i.test(ua)) os = "Android";
                else if (/Macintosh/i.test(ua)) os = "macOS";
                else if (/Linux/i.test(ua)) os = "Linux";

                let browser = "Other";
                if (/Instagram/i.test(ua)) browser = "Instagram";
                else if (/TikTok/i.test(ua)) browser = "TikTok";
                else if (/FBAN|FBAV/i.test(ua)) browser = "Facebook";
                else if (/Chrome/i.test(ua)) browser = "Chrome";
                else if (/Safari/i.test(ua)) browser = "Safari";
                else if (/Firefox/i.test(ua)) browser = "Firefox";
                else if (/Edg/i.test(ua)) browser = "Edge";

                let device = "Desktop";
                if (/Mobi|Android/i.test(ua)) device = "Mobile";
                else if (/Tablet|iPad/i.test(ua)) device = "Tablet";

                let country = "Unknown";
                let countryCode = "";
                try {
                    const controller = new AbortController();
                    const timeoutId = setTimeout(() => controller.abort(), 3000); // 3s timeout

                    const res = await fetch("https://ipapi.co/json/", { signal: controller.signal }).then(r => r.json());
                    clearTimeout(timeoutId);

                    country = res.country_name || "Unknown";
                    countryCode = res.country || "";
                } catch (e) { console.error("Geo failed or timed out", e); }

                // Referrer normalization
                let referrer = "Direct";
                const ref = document.referrer;
                if (ref) {
                    try {
                        const url = new URL(ref);
                        referrer = url.hostname;
                        if (referrer.includes("instagram.com")) referrer = "Instagram";
                        else if (referrer.includes("t.co")) referrer = "Twitter";
                        else if (referrer.includes("facebook.com")) referrer = "Facebook";
                        else if (referrer.includes("tiktok.com")) referrer = "TikTok";
                        else if (referrer.includes("google.com")) referrer = "Google";
                    } catch (e) { referrer = "Other"; }
                }

                // Uniqueness check
                const today = new Date().toISOString().split('T')[0];
                const storageKey = `gr_unique_${link.id}_${today}`;
                const isUnique = !localStorage.getItem(storageKey);
                if (isUnique) {
                    localStorage.setItem(storageKey, "1");
                }

                // 4. Determine Destination
                let finalDestination = link.destination_url;
                if (link.geo_targeting && countryCode && link.geo_targeting[countryCode]) {
                    finalDestination = link.geo_targeting[countryCode];
                }
                if (link.device_targeting && link.device_targeting[device]) {
                    finalDestination = link.device_targeting[device];
                }
                if (link.ab_split && Array.isArray(link.split_urls) && link.split_urls.length > 0) {
                    const allOptions = [finalDestination, ...link.split_urls];
                    finalDestination = allOptions[Math.floor(Math.random() * allOptions.length)];
                }
                setDestination(finalDestination);

                // Log click before redirect (if not a bot)
                if (!isBot) {
                    await pb.collection('clicks').create({
                        link_id: link.id,
                        country,
                        device,
                        os,
                        browser,
                        referrer,
                        is_unique: isUnique,
                        ip: "masked",
                        user_agent: ua.slice(0, 200)
                    });
                    await pb.collection('links').update(link.id, { 'clicks_count+': 1 });
                }

                // 5. Advanced Deep Link Escape (Special mode)
                if (link.mode === 'direct' && isInApp) {
                    setStatus("deeplink");

                    // Escape Strategy for Android (Intents)
                    if (/Android/i.test(ua)) {
                        const scheme = finalDestination.replace(/^https?:\/\//, "");
                        const intentUrl = `intent://${scheme}#Intent;scheme=https;package=com.android.chrome;end`;
                        window.location.href = intentUrl;
                    }

                    // Fallback attempt for iOS/Other
                    setTimeout(() => {
                        window.location.href = finalDestination;
                    }, 500);

                    return;
                }

                // 6. Interstitial / Mobile Guard Logic
                const needsInterstitial = link.mode === 'landing' || link.interstitial_enabled;

                if (needsInterstitial) {
                    setStatus("verifying");

                    const performFinalAction = () => {
                        window.location.replace(finalDestination);
                    };

                    const interactionHandler = () => {
                        window.removeEventListener('touchstart', interactionHandler);
                        window.removeEventListener('click', interactionHandler);
                        performFinalAction();
                    };

                    window.addEventListener('touchstart', interactionHandler);
                    window.addEventListener('click', interactionHandler);
                } else {
                    // Standard Fast Redirect
                    window.location.replace(finalDestination);
                }

            } catch (err: any) {
                console.error("Redirection error:", err);
                setStatus("error");
                setError("An error occurred during redirection");
            }
        };

        handleRedirect();
    }, [username, navigate]);

    if (status === "profile") {
        return <PublicProfile />;
    }

    if (status === "loading") {
        // ... (rest of the file)
        return (
            <div className="min-h-screen bg-black flex flex-col items-center justify-center p-4">
                <Loader2 className="w-12 h-12 text-accent animate-spin mb-4" />
                <p className="text-muted-foreground text-sm animate-pulse">Loading destination...</p>
            </div>
        );
    }

    if (status === "deeplink") {
        return (
            <div className="min-h-screen bg-background flex flex-col items-center justify-center p-8 text-center animate-fade-in">
                <div className="relative mb-10">
                    <div className="absolute inset-0 bg-accent/20 blur-3xl rounded-full animate-pulse" />
                    <div className="relative w-28 h-28 rounded-[2.5rem] bg-surface border border-accent/30 flex items-center justify-center shadow-2xl shadow-accent/20">
                        <Compass className="w-14 h-14 text-accent animate-spin-slow" />
                    </div>
                </div>

                <div className="space-y-4 mb-10 max-w-sm">
                    <h1 className="text-3xl font-bold text-foreground">Opening Link...</h1>
                    <p className="text-muted-foreground text-sm leading-relaxed">
                        We are attempting to open this link in your system browser for a better experience.
                    </p>
                </div>

                {/* Manual Fallback Assistance */}
                <div className="w-full max-w-sm space-y-4">
                    <a
                        href={destination}
                        className="btn-primary-glow w-full flex items-center justify-center gap-2 py-4 text-lg"
                    >
                        <ExternalLink className="w-5 h-5" />
                        Open in Browser
                    </a>

                    <div className="bg-surface/50 border border-border rounded-2xl p-6 text-left space-y-4">
                        <p className="text-xs font-semibold text-accent uppercase tracking-wider">How to open manually:</p>

                        <div className="flex items-start gap-3">
                            <div className="w-6 h-6 rounded-lg bg-background border border-border flex items-center justify-center text-xs font-bold text-foreground mt-0.5">1</div>
                            <p className="text-xs text-muted-foreground">Tap the <span className="text-foreground inline-flex items-center gap-1 bg-background px-1.5 py-0.5 rounded border border-border"><MoreVertical className="w-3 h-3" /> menu</span> in top right corner.</p>
                        </div>

                        <div className="flex items-start gap-3">
                            <div className="w-6 h-6 rounded-lg bg-background border border-border flex items-center justify-center text-xs font-bold text-foreground mt-0.5">2</div>
                            <p className="text-xs text-muted-foreground">Select <span className="text-foreground font-semibold">"Open in Browser"</span> or <span className="text-foreground font-semibold">"Open in Chrome/Safari"</span>.</p>
                        </div>
                    </div>
                </div>

                <button
                    onClick={() => window.location.replace(destination)}
                    className="mt-8 text-xs text-muted-foreground hover:text-accent transition-colors flex items-center gap-1.5"
                >
                    <Share2 className="w-3 h-3" />
                    Skip optimization
                </button>
            </div>
        );
    }

    if (status === "verifying") {
        return (
            <div className="min-h-screen bg-black flex flex-col items-center justify-center p-8 text-center animate-fade-in">
                <div className="relative mb-8">
                    <div className="absolute inset-0 bg-accent/20 blur-3xl rounded-full" />
                    <div className="relative w-24 h-24 rounded-3xl bg-surface border border-accent/30 flex items-center justify-center">
                        <Smartphone className="w-10 h-10 text-accent animate-bounce" />
                    </div>
                </div>
                <h1 className="text-2xl font-bold text-foreground mb-3">Security Check</h1>
                <p className="text-muted-foreground mb-8 max-w-xs mx-auto">
                    Please tap anywhere on the screen to confirm you are not a robot.
                </p>
                <div className="w-full max-w-xs h-1 bg-surface rounded-full overflow-hidden">
                    <div className="h-full bg-accent animate-shimmer" style={{ width: '40%' }} />
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-background flex flex-col items-center justify-center">
            <div className="glass-card p-12 flex flex-col items-center gap-6 animate-pulse">
                <Loader2 className="w-10 h-10 animate-spin text-accent" />
                <p className="text-lg font-medium text-foreground">Redirecting you smartly...</p>
            </div>
        </div>
    );
}

import { useState, useEffect } from "react";
import { pb } from "@/lib/pocketbase";
import { Search, ChevronLeft, ChevronRight, Ban, Check, ExternalLink, BarChart3, SortDesc, Share2 } from "lucide-react";
import { toast } from "sonner";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle, AlertDialogTrigger } from "@/components/ui/alert-dialog";
import { useNavigate } from "react-router-dom";

type LinkRecord = {
    id: string;
    destination_url: string;
    slug: string;
    active: boolean;
    clicks_count: number;
    user_id: string;
    created: string;
    expand?: {
        user_id?: {
            email: string;
        }
    }
};

export default function AdminLinks() {
    const navigate = useNavigate();
    const [links, setLinks] = useState<LinkRecord[]>([]);
    const [loading, setLoading] = useState(true);
    const [page, setPage] = useState(1);
    const [totalPages, setTotalPages] = useState(1);
    const [search, setSearch] = useState("");
    const [sortClicks, setSortClicks] = useState(false);

    const fetchLinks = async () => {
        setLoading(true);
        try {
            const sortQuery = sortClicks ? "-clicks_count,-created" : "-created";
            let filterQuery = "";

            if (search) {
                filterQuery = `destination_url ~ "${search}" || slug ~ "${search}"`;
            }

            const result = await pb.collection("links").getList(page, 20, {
                sort: sortQuery,
                filter: filterQuery,
                expand: 'user_id',
                requestKey: null
            });
            setLinks(result.items as any[]);
            setTotalPages(result.totalPages);
        } catch (err) {
            console.error("Failed to fetch links", err);
            toast.error("Failed to load links");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchLinks();
    }, [page, search, sortClicks]);

    const toggleLinkStatus = async (linkId: string, currentStatus: boolean) => {
        try {
            await pb.collection("links").update(linkId, { active: !currentStatus });
            toast.success(currentStatus ? "Link deactivated" : "Link activated");
            setLinks(links.map(l => l.id === linkId ? { ...l, active: !currentStatus } : l));
        } catch (err) {
            console.error("Failed to toggle link status", err);
            toast.error("Could not update link status");
        }
    };

    return (
        <div className="space-y-6 pt-6 max-w-6xl mx-auto">
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                <div className="flex items-center gap-4">
                    <button
                        onClick={() => navigate('/dashboard')}
                        className="p-2 -ml-2 rounded-lg text-muted-foreground hover:bg-surface-hover hover:text-foreground transition-colors"
                    >
                        <ChevronLeft className="w-5 h-5" />
                    </button>
                    <div>
                        <h1 className="text-2xl font-bold text-foreground">Links Oversight</h1>
                        <p className="text-sm text-muted-foreground mt-1">Monitor and moderate all short links</p>
                    </div>
                </div>

                <div className="flex flex-col sm:flex-row items-center gap-3">
                    <button
                        onClick={() => { setSortClicks(!sortClicks); setPage(1); }}
                        className={`flex items-center gap-2 px-3 py-2 rounded-xl text-sm font-medium border transition-colors ${sortClicks ? 'bg-accent/10 text-accent border-accent/20' : 'bg-surface border-border text-muted-foreground hover:text-foreground'
                            }`}
                    >
                        <SortDesc className="w-4 h-4" />
                        Most Clicks
                    </button>

                    <div className="relative w-full sm:w-72">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                        <input
                            type="text"
                            placeholder="Search URL or slug..."
                            value={search}
                            onChange={(e) => { setSearch(e.target.value); setPage(1); }}
                            className="w-full pl-9 pr-4 py-2 bg-surface border border-border rounded-xl text-sm focus:outline-none focus:border-accent/50 transition-all placeholder:text-muted-foreground"
                        />
                    </div>
                </div>
            </div>

            <div className="bg-surface border border-border rounded-2xl overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full">
                        <thead>
                            <tr className="border-b border-border bg-sidebar-accent/30 text-left text-xs font-semibold text-muted-foreground uppercase tracking-wider">
                                <th className="px-6 py-4">Link Details</th>
                                <th className="px-6 py-4">Owner</th>
                                <th className="px-6 py-4 text-right">Clicks</th>
                                <th className="px-6 py-4">Status</th>
                                <th className="px-6 py-4 text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-border">
                            {loading ? (
                                <tr>
                                    <td colSpan={5} className="px-6 py-12 text-center text-muted-foreground">
                                        <div className="w-6 h-6 border-2 border-accent border-t-transparent rounded-full animate-spin mx-auto" />
                                    </td>
                                </tr>
                            ) : links.length === 0 ? (
                                <tr>
                                    <td colSpan={5} className="px-6 py-12 text-center text-muted-foreground">
                                        No links found matching your criteria.
                                    </td>
                                </tr>
                            ) : (
                                links.map((link) => {
                                    const shortUrl = `${window.location.host}/${link.slug}`;
                                    return (
                                        <tr key={link.id} className="hover:bg-surface-hover transition-colors">
                                            <td className="px-6 py-4">
                                                <div className="flex flex-col max-w-[250px] sm:max-w-xs md:max-w-sm">
                                                    <a href={`http://${shortUrl}`} target="_blank" rel="noopener noreferrer" className="font-medium text-accent hover:underline flex items-center gap-1.5 truncate">
                                                        {shortUrl}
                                                        <ExternalLink className="w-3 h-3 shrink-0" />
                                                    </a>
                                                    <span className="text-xs text-muted-foreground truncate mt-1" title={link.destination_url}>
                                                        {link.destination_url}
                                                    </span>
                                                    <span className="text-[10px] text-muted-foreground/70 mt-1">
                                                        {new Date(link.created).toLocaleString()}
                                                    </span>
                                                </div>
                                            </td>
                                            <td className="px-6 py-4">
                                                <div className="flex items-center gap-2">
                                                    <code className="text-xs font-mono bg-background border border-border px-1.5 py-0.5 rounded text-foreground">
                                                        {link.user_id}
                                                    </code>
                                                    <button
                                                        onClick={() => {
                                                            navigator.clipboard.writeText(link.user_id);
                                                            toast.success("User ID copied to clipboard");
                                                        }}
                                                        className="text-muted-foreground hover:text-foreground transition-colors p-1"
                                                        title="Copy User ID"
                                                    >
                                                        <Share2 className="w-3 h-3" />
                                                    </button>
                                                </div>
                                            </td>
                                            <td className="px-6 py-4 text-right">
                                                <div className="inline-flex items-center justify-end gap-1.5 px-2 py-1 rounded bg-background border border-border min-w-[60px]">
                                                    <BarChart3 className="w-3.5 h-3.5 text-accent" />
                                                    <span className="text-sm font-medium">{link.clicks_count || 0}</span>
                                                </div>
                                            </td>
                                            <td className="px-6 py-4">
                                                <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium ${!link.active ? 'bg-red-500/10 text-red-500' : 'bg-accent/10 text-accent'
                                                    }`}>
                                                    {!link.active ? <Ban className="w-3 h-3" /> : <Check className="w-3 h-3" />}
                                                    {!link.active ? 'Disabled' : 'Active'}
                                                </span>
                                            </td>
                                            <td className="px-6 py-4 text-right">
                                                <div className="flex items-center justify-end gap-2">
                                                    <AlertDialog>
                                                        <AlertDialogTrigger asChild>
                                                            <button className={`p-2 rounded-lg transition-colors ${link.active
                                                                ? 'text-muted-foreground hover:bg-red-500/10 hover:text-red-500'
                                                                : 'text-muted-foreground hover:bg-accent/10 hover:text-accent'
                                                                }`}>
                                                                {link.active ? <Ban className="w-4 h-4" /> : <Check className="w-4 h-4" />}
                                                            </button>
                                                        </AlertDialogTrigger>
                                                        <AlertDialogContent className="bg-surface border-border">
                                                            <AlertDialogHeader>
                                                                <AlertDialogTitle className="text-foreground">
                                                                    {link.active ? 'Deactivate Link?' : 'Activate Link?'}
                                                                </AlertDialogTitle>
                                                                <AlertDialogDescription className="text-muted-foreground">
                                                                    {link.active
                                                                        ? "This will cause the link to show an error or interstitial page instead of redirecting the user. Use this for spam or abuse."
                                                                        : "This will restore functionality to the link and allow it to redirect users normally."}
                                                                </AlertDialogDescription>
                                                            </AlertDialogHeader>
                                                            <AlertDialogFooter>
                                                                <AlertDialogCancel className="bg-background border-border text-foreground hover:bg-surface-hover">Cancel</AlertDialogCancel>
                                                                <AlertDialogAction
                                                                    className={link.active ? "bg-red-500 hover:bg-red-600 text-white" : "bg-accent hover:bg-accent/90 text-white"}
                                                                    onClick={() => toggleLinkStatus(link.id, link.active)}
                                                                >
                                                                    {link.active ? "Yes, Deactivate" : "Yes, Activate"}
                                                                </AlertDialogAction>
                                                            </AlertDialogFooter>
                                                        </AlertDialogContent>
                                                    </AlertDialog>
                                                </div>
                                            </td>
                                        </tr>
                                    )
                                })
                            )}
                        </tbody>
                    </table>
                </div>

                {/* Pagination */}
                {totalPages > 1 && (
                    <div className="px-6 py-4 border-t border-border flex items-center justify-between">
                        <span className="text-sm text-muted-foreground">
                            Page {page} of {totalPages}
                        </span>
                        <div className="flex gap-2">
                            <button
                                disabled={page === 1}
                                onClick={() => setPage(p => Math.max(1, p - 1))}
                                className="p-2 border border-border rounded-lg disabled:opacity-50 text-foreground hover:bg-surface-hover transition-colors"
                            >
                                <ChevronLeft className="w-4 h-4" />
                            </button>
                            <button
                                disabled={page === totalPages}
                                onClick={() => setPage(p => Math.min(totalPages, p + 1))}
                                className="p-2 border border-border rounded-lg disabled:opacity-50 text-foreground hover:bg-surface-hover transition-colors"
                            >
                                <ChevronRight className="w-4 h-4" />
                            </button>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
}
